int add_macro(uint8_t trigger_mod, uint8_t trigger_key, uint8_t mod_mask,
              std::vector<MacroStep> steps) {
    Macro m;
    m.trigger_mod = trigger_mod;
    m.trigger_key = trigger_key;
    m.mod_mask = mod_mask;
    m.steps = std::move(steps);
    macros.push_back(std::move(m));
    return static_cast<int>(macros.size()) - 1;
}
