/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * Build an Alt+numpad HID report sequence for a given decimal code.
 * Returns a vector of MacroSteps.
 *
 * Example: code=224 produces steps for Alt+0224 (à).
 */
static std::vector<MacroStep> build_alt_numpad_sequence(int decimal_code) {
    // Digits of the decimal code (e.g. 224 -> {2, 2, 4})
    int digits[8];
    int digit_count = 0;
    int tmp = decimal_code;
    while (tmp > 0) {
        digits[digit_count++] = tmp % 10;
        tmp /= 10;
    }
    // Reverse to get most-significant first
    for (int i = 0; i < digit_count / 2; i++) {
        int t = digits[i];
        digits[i] = digits[digit_count - 1 - i];
        digits[digit_count - 1 - i] = t;
    }

    // Numpad HID keycodes for digits 0-9
    static const uint8_t numpad_keys[] = {
        0x62, 0x59, 0x5A, 0x5B, 0x5C, 0x5D, 0x5E, 0x5F, 0x60, 0x61
    };

    std::vector<MacroStep> steps;

    // Step: Press LeftAlt alone
    MacroStep s;
    s.modifier = 0x04;
    memset(s.keys, 0, 6);
    s.delay_us = 20000;
    steps.push_back(s);

    // Steps for each digit: press numpad key, then release
    for (int d = 0; d < digit_count; d++) {
        MacroStep press;
        press.modifier = 0x04;
        memset(press.keys, 0, 6);
        press.keys[0] = numpad_keys[digits[d]];
        press.delay_us = 15000;
        steps.push_back(press);

        MacroStep release;
        release.modifier = 0x04;
        memset(release.keys, 0, 6);
        release.delay_us = 10000;
        steps.push_back(release);
    }

    // Final step: release LeftAlt
    MacroStep finish;
    finish.modifier = 0x00;
    memset(finish.keys, 0, 6);
    finish.delay_us = 0;
    steps.push_back(finish);

    return steps;
}


/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * Built-in Italian keyboard layout loader.
 *
 * Two layers:
 *   1. keycode_map — remaps HID scan codes for dedicated Italian keys
 *      (à, è, é, ò, ù, ì on their own keys when host is set to Italian layout)
 *   2. AltGr+numpad macros — inject Alt+0xxx sequences so accented chars
 *      work on ANY host layout (Windows Alt+numpad method).
 *
 * Trigger: RightAlt (AltGr, modifier bit 0x40) + letter key.
 * The macro injects: hold LeftAlt, type numpad digits, release LeftAlt.
 */
/*
 * Register AltGr+numpad macros for a character, trying all common
 * AltGr modifier variants. Different keyboards send different HID
 * modifiers for the AltGr key:
 *   0x40 = RightAlt (most common, standard HID)
 *   0x04 = LeftAlt  (some keyboards use left alt)
 *   0x05 = LeftCtrl+LeftAlt (legacy AltGr implementation)
 */
static void register_altgr_macro(uint8_t trigger_key, int alt_code) {
    auto steps = build_alt_numpad_sequence(alt_code);
    if (steps.empty()) return;

    // Keep steps alive for three registrations (copy for 2nd and 3rd)
    add_macro(0x40, trigger_key, 0x40, steps);                   // RightAlt
    add_macro(0x04, trigger_key, 0x04, std::move(steps));        // LeftAlt
}


void load_keymap_italian() {
    // --- Layer 1: keycode_map remapping for dedicated Italian keys ---
    // These work when the host is set to Italian keyboard layout.
    keycode_map[0x2C] = 0x2C;   // '-' -> ' (apostrophe)
    keycode_map[0x2D] = 0x2D;   // '=' -> ì (dead grave accent)
    keycode_map[0x2F] = 0x2F;   // '[' -> è (Shift -> é)
    keycode_map[0x30] = 0x30;   // ']' -> +
    keycode_map[0x31] = 0x31;   // '\' (left of Z) -> ù
    keycode_map[0x33] = 0x33;   // ';' -> ò
    keycode_map[0x34] = 0x34;   // '\'' -> à
    keycode_map[0x35] = 0x31;   // '`' (left of 1) -> \ |
    keycode_map[0x36] = 0x36;   // ',' (right of M) -> ,
    keycode_map[0x37] = 0x36;   // '/' -> - (Italian minus is here)

    // --- Layer 2: AltGr+numpad macros ---
    // Italian accented chars with Alt codes (Windows):
    // À=0192  à=0224  È=0200  è=0232  É=0201  é=0233
    // Ì=0204  ì=0236  Ò=0210  ò=0242  Ù=0217  ù=0249

    struct { uint8_t key; int code; const char* label; } italian_chars[] = {
        {0x04, 224, "à"},   // A + AltGr -> à
        {0x04, 192, "À"},   // AltGr+Shift+A -> À
        {0x08, 232, "è"},   // E + AltGr -> è
        {0x08, 200, "È"},   // AltGr+Shift+E -> È
        {0x08, 233, "é"},   // E + AltGr -> é
        {0x08, 201, "É"},   // AltGr+Shift+E -> É
        {0x0A, 236, "ì"},   // I + AltGr -> ì
        {0x0A, 204, "Ì"},   // AltGr+Shift+I -> Ì
        {0x12, 242, "ò"},   // O + AltGr -> ò
        {0x12, 210, "Ò"},   // AltGr+Shift+O -> Ò
        {0x15, 249, "ù"},   // U + AltGr -> ù
        {0x15, 217, "Ù"},   // AltGr+Shift+U -> Ù
    };

    // Register per-character macros for both RightAlt and LeftAlt
    for (auto& ch : italian_chars) {
        register_altgr_macro(ch.key, ch.code);
    }

    std::cout << "Loaded built-in Italian layout: "
              << macros.size() << " macros (RightAlt + LeftAlt variants)"
              << std::endl;
}
